params.functionCall:
{
    "name": "dialogue_completed",
    "description": "聴取した内容を予約・変更・キャンセル・問合せのいずれかに分類して保存します。",
    "strict": true,
    "parameters": {
        "type": "object",
        "properties": {
            "classification": {
                "type": "string",
                "description": "受付区分（変更、キャンセル、予約、問合せ、またはNO_RESULT）",
                "display_type": "classification",
                "enum": [
                    "変更",
                    "キャンセル",
                    "予約",
                    "問合せ",
                    "NO_RESULT"
                ]
            }
        },
        "required": [
            "classification"
        ],
        "additionalProperties": false
    }
}

params.script:
var rawData = $runner.getModuleResult("save-携帯電話");
var d = rawData ? String(rawData).replace(/[^0-9]/g, "") : "";
var res = "INVALID";

var mobilePattern = /^0(50|60|70|80|90)\d{8}$/;
var fixedPattern = /^0(?!(50|60|70|80|90))\d{9,10}$/;

if (d && (mobilePattern.test(d) || fixedPattern.test(d))) {
    // 【維持】「にー」「ごー」の長音化
    var m = ["ぜろ", "いち", "にー", "さん", "よん", "ごー", "ろく", "なな", "はち", "きゅう"];
    
    // 速度 90%
    var ssml = "<prosody rate='90%'>";
    
    for (var i = 0; i < d.length; i++) {
        var n = parseInt(d.charAt(i), 10);
        
        // 数字ごとの間（50ms）
        ssml += "<sub alias='" + m[n] + "'>" + d.charAt(i) + "</sub><break time='50ms'/>";

        // 区切り（の）のリズム制御
        var isPause = false;
        if (d.length == 11) {
            if (i == 2 || i == 6) isPause = true;
        } else if (d.length == 10) {
            var prefix2 = d.substring(0, 2);
            if (prefix2 == "03" || prefix2 == "06") {
                if (i == 1 || i == 5) isPause = true;
            } else {
                if (i == 2 || i == 5) isPause = true;
            }
        }

        if (isPause) {
            // 【修正点】「の」の前にも 300ms の間を追加
            // これで「数字（50ms）＋（300ms）＋ の ＋（400ms）＋ 数字」となります
            ssml += "<break time='300ms'/>の、<break time='400ms'/>";
        }
    }
    
    // 最後の間（600ms）
    ssml += "<break time='600ms'/>";
    ssml += "</prosody>";
    res = ssml;
}

$runner.setResult(res);
